parameters.jsCode:
// n8n Code node (Run Once for Each Item)

const startOfThread = $input.item.json.messages.find(m => m.thread_ts == m.ts);

// 1) Get Missive draft id from the earlier node
//    Adjust this path if your field name is different.
const followupDraftId =$('Save Followup Draft Id').item.json.followupDraftId

// 2) Build the Missive draft URL
const missiveDraftUrl =
  `https://mail.missiveapp.com/#drafts/conversations/${followupDraftId}`;

// 3) Clone blocks so we can safely mutate them
const blocks = JSON.parse(JSON.stringify(startOfThread.blocks || []));

// 4) Find the first actions block and append a new button
const actionsBlock = blocks.find(b => b.type === 'actions');

if (actionsBlock) {
  actionsBlock.elements = actionsBlock.elements
    .filter(e => e.action_id !=='open_missive_draft')
    .concat({
        "type": "button",
        "action_id": "open_missive_draft",
        "text": {
          "type": "plain_text",
          "text": "✉️ Open draft",
          "emoji": true
        },
        "value": `open_missive_draft_${followupDraftId}`,
        "url": missiveDraftUrl,
   });
}

return { blocks, ts: startOfThread.ts, };

